const App = () => (
  <Provider store = {store}>
  <Router>
    <Fragment>
      <Navbar />

      <section className='container'>
        <Routes>
          <Route exact path='/register' element={<Register />} />
          <Route exact path='/login' element={<Login />} />
        </Routes>
      </section>
    </Fragment>
  </Router>
  </Provider>
);

export default App;
